    { name: "Thomas R.", xp: 1820, role: "challenger" },
    { name: "Julie M.", xp: 1540, role: "challenger" },
    { name: "Lucas D.", xp: 1280, role: "apprenant" },
    { name: "Emma B.", xp: 980, role: "apprenant" },
