import { useEffect } from "react";
import { useLocation } from "wouter";
import { motion } from "framer-motion";
import { StemFlowLogo, StemFlowSlogan } from "@/components/StemFlowLogo";
import { Button } from "@/components/ui/button";
import { ThemeToggle } from "@/components/ThemeToggle";
import { useUserState } from "@/lib/userState";
import { ChevronRight, Sparkles, Users, Target, Zap } from "lucide-react";

export default function Home() {
  const [, setLocation] = useLocation();
  const { onboardingCompleted } = useUserState();

  useEffect(() => {
    if (onboardingCompleted) {
      setLocation("/feed");
    }
  }, [onboardingCompleted, setLocation]);

  const features = [
    {
      icon: Sparkles,
      title: "Contenu personnalisé",
      description: "Un feed adapté à tes intérêts et ton niveau",
      gradient: "gradient-stem",
    },
    {
      icon: Users,
      title: "Communautés STEM",
      description: "Rejoins des salons et apprends avec d'autres",
      gradient: "bg-primary",
    },
    {
      icon: Target,
      title: "Missions quotidiennes",
      description: "Complète des défis et gagne des XP",
      gradient: "gradient-energy",
    },
    {
      icon: Zap,
      title: "Progression gamifiée",
      description: "Monte de niveau et deviens un expert",
      gradient: "bg-accent",
    },
  ];

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-background/90 backdrop-blur-xl border-b">
        <div className="flex items-center justify-between p-4 max-w-lg mx-auto">
          <StemFlowLogo size="sm" />
          <ThemeToggle />
        </div>
      </header>

      {/* Hero Section */}
      <main className="pt-20 pb-32">
        <div className="px-6 py-12 text-center max-w-lg mx-auto">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            <div className="mb-6">
              <StemFlowLogo size="xl" showText={false} className="justify-center mb-4" />
              <h1 className="text-4xl font-bold gradient-stem-text mb-2">
                STEM FLOW
              </h1>
              <StemFlowSlogan className="text-lg" />
            </div>

            <p className="text-muted-foreground mb-8 text-lg">
              Découvre les sciences, la technologie, l'ingénierie et les mathématiques
              de manière fun, sociale et engageante.
            </p>

            <Button
              size="lg"
              className="gradient-stem text-white text-lg px-8 py-6"
              onClick={() => setLocation("/onboarding")}
              data-testid="button-start"
            >
              Commencer l'aventure
              <ChevronRight className="h-5 w-5 ml-2" />
            </Button>
          </motion.div>
        </div>

        {/* Features */}
        <div className="px-6 space-y-4 max-w-lg mx-auto">
          {features.map((feature, index) => {
            const Icon = feature.icon;
            return (
              <motion.div
                key={feature.title}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.2 + index * 0.1 }}
                className="flex items-center gap-4 p-4 rounded-xl bg-card border"
              >
                <div className={`p-3 rounded-lg ${feature.gradient}`}>
                  <Icon className="h-6 w-6 text-white" />
                </div>
                <div>
                  <h3 className="font-semibold">{feature.title}</h3>
                  <p className="text-sm text-muted-foreground">{feature.description}</p>
                </div>
              </motion.div>
            );
          })}
        </div>

        {/* Stats */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.6 }}
          className="px-6 py-8 mt-8 max-w-lg mx-auto"
        >
          <div className="grid grid-cols-3 gap-4 text-center p-6 rounded-xl bg-gradient-to-br from-primary/10 to-accent/10 border">
            <div>
              <div className="text-2xl font-bold text-primary">1000+</div>
              <div className="text-xs text-muted-foreground">Contenus</div>
            </div>
            <div>
              <div className="text-2xl font-bold text-accent">50+</div>
              <div className="text-xs text-muted-foreground">Salons</div>
            </div>
            <div>
              <div className="text-2xl font-bold text-[#F5B700]">10K+</div>
              <div className="text-xs text-muted-foreground">Apprenants</div>
            </div>
          </div>
        </motion.div>
      </main>

      {/* Bottom CTA */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-background/80 backdrop-blur-lg border-t">
        <div className="max-w-lg mx-auto">
          <Button
            className="w-full gradient-stem text-white"
            size="lg"
            onClick={() => setLocation("/onboarding")}
            data-testid="button-start-bottom"
          >
            <Sparkles className="h-5 w-5 mr-2" />
            Rejoindre STEM FLOW
          </Button>
        </div>
      </div>
    </div>
  );
}

client/src/pages/Rooms.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { motion } from "framer-motion";
import { StemFlowLogo } from "@/components/StemFlowLogo";
import { ThemeToggle } from "@/components/ThemeToggle";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { BottomNav } from "@/components/BottomNav";
import {
  Users,
  Lightbulb,
  Cpu,
  Wrench,
  Calculator,
  Lock,
  Globe,
  ChevronRight,
  Plus,
  Zap,
  Flame,
} from "lucide-react";
import type { Room } from "@shared/schema";
import { useUserState } from "@/lib/userState";

const categoryIcons = {
  science: Lightbulb,
  technology: Cpu,
  engineering: Wrench,
  mathematics: Calculator,
};

const categoryColors = {
  science: "from-blue-500 to-cyan-400",
  technology: "from-purple-500 to-pink-400",
  engineering: "from-orange-500 to-yellow-400",
  mathematics: "from-green-500 to-emerald-400",
};

export default function Rooms() {
  const [, setLocation] = useLocation();
  const { xp, streak } = useUserState();

  const { data: rooms, isLoading } = useQuery<Room[]>({
    queryKey: ["/api/rooms"],
  });

  return (
    <div className="min-h-screen bg-background pb-20">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-background/90 backdrop-blur-xl border-b">
        <div className="flex items-center justify-between gap-3 p-4">
          <div>
            <h1 className="text-xl font-bold">Salons</h1>
            <p className="text-sm text-muted-foreground">Rejoins une communaut\u00e9</p>
          </div>
          <div className="flex items-center gap-3">
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-[#F5B700]/10">
              <Flame className="h-3.5 w-3.5 text-[#F5B700]" />
              <span className="text-xs font-bold text-[#F5B700]">{streak}</span>
            </div>
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-accent/10">
              <Zap className="h-3.5 w-3.5 text-accent" />
              <span className="text-xs font-bold text-accent">{xp}</span>
            </div>
            <ThemeToggle />
          </div>
        </div>
      </header>

      {/* Rooms List */}
      <main className="p-4 space-y-4 max-w-lg mx-auto">
        {/* Create Room Button */}
        <Button
          className="w-full gradient-stem text-white"
          data-testid="button-create-room"
        >
          <Plus className="h-4 w-4 mr-2" />
          Créer un salon
        </Button>

        {isLoading ? (
          <>
            {[1, 2, 3, 4].map((i) => (
              <Card key={i} className="p-4">
                <div className="flex items-center gap-4">
                  <Skeleton className="h-14 w-14 rounded-lg" />
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-5 w-40" />
                    <Skeleton className="h-4 w-full" />
                    <Skeleton className="h-3 w-24" />
                  </div>
                </div>
              </Card>
            ))}
          </>
        ) : rooms && rooms.length > 0 ? (
          rooms.map((room, index) => {
            const CategoryIcon = categoryIcons[room.category];
            const gradientColor = categoryColors[room.category];

            return (
              <motion.div
                key={room.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <Card
                  className="p-4 hover-elevate cursor-pointer"
                  onClick={() => setLocation(`/rooms/${room.id}`)}
                  data-testid={`room-card-${room.id}`}
                >
                  <div className="flex items-center gap-4">
                    <div className={`p-3 rounded-lg bg-gradient-to-br ${gradientColor}`}>
                      <CategoryIcon className="h-8 w-8 text-white" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-semibold truncate">{room.name}</h3>
                        {room.type === "private" ? (
                          <Lock className="h-4 w-4 text-muted-foreground" />
                        ) : (
                          <Globe className="h-4 w-4 text-muted-foreground" />
                        )}
                      </div>
                      <p className="text-sm text-muted-foreground line-clamp-1 mb-2">
                        {room.description}
                      </p>
                      <div className="flex items-center gap-2">
                        <Badge variant="secondary" className="text-xs">
                          <Users className="h-3 w-3 mr-1" />
                          {room.memberCount} membres
                        </Badge>
                        <Badge variant="outline" className="text-xs capitalize">
                          {room.category}
                        </Badge>
                      </div>
                    </div>
                    <ChevronRight className="h-5 w-5 text-muted-foreground" />
                  </div>
                </Card>
              </motion.div>
            );
          })
        ) : (
          <div className="text-center py-12">
            <div className="inline-flex p-4 rounded-full bg-muted mb-4">
              <Users className="h-8 w-8 text-muted-foreground" />
            </div>
            <h3 className="text-lg font-semibold mb-2">Aucun salon</h3>
            <p className="text-muted-foreground mb-4">
              Sois le premier à créer un salon !
            </p>
          </div>
        )}
      </main>

      <BottomNav />
    </div>
  );
}

