import * as React from "react"
import { OTPInput, OTPInputContext } from "input-otp"
import { Dot } from "lucide-react"

import { cn } from "@/lib/utils"

const InputOTP = React.forwardRef<
  React.ElementRef<typeof OTPInput>,
  React.ComponentPropsWithoutRef<typeof OTPInput>
>(({ className, containerClassName, ...props }, ref) => (
  <OTPInput
    ref={ref}
    containerClassName={cn(
      "flex items-center gap-2 has-[:disabled]:opacity-50",
      containerClassName
    )}
    className={cn("disabled:cursor-not-allowed", className)}
    {...props}
  />
))
InputOTP.displayName = "InputOTP"

const InputOTPGroup = React.forwardRef<
  React.ElementRef<"div">,
  React.ComponentPropsWithoutRef<"div">
>(({ className, ...props }, ref) => (
  <div ref={ref} className={cn("flex items-center", className)} {...props} />
))
InputOTPGroup.displayName = "InputOTPGroup"

const InputOTPSlot = React.forwardRef<
  React.ElementRef<"div">,
  React.ComponentPropsWithoutRef<"div"> & { index: number }
>(({ index, className, ...props }, ref) => {
  const inputOTPContext = React.useContext(OTPInputContext)
  const { char, hasFakeCaret, isActive } = inputOTPContext.slots[index]

  return (
    <div
      ref={ref}
      className={cn(
        "relative flex h-10 w-10 items-center justify-center border-y border-r border-input text-sm transition-all first:rounded-l-md first:border-l last:rounded-r-md",
        isActive && "z-10 ring-2 ring-ring ring-offset-background",
        className
      )}
      {...props}
    >
      {char}
      {hasFakeCaret && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
          <div className="h-4 w-px animate-caret-blink bg-foreground duration-1000" />
        </div>
      )}
    </div>
  )
})
InputOTPSlot.displayName = "InputOTPSlot"

const InputOTPSeparator = React.forwardRef<
  React.ElementRef<"div">,
  React.ComponentPropsWithoutRef<"div">
>(({ ...props }, ref) => (
  <div ref={ref} role="separator" {...props}>
    <Dot />
  </div>
))
InputOTPSeparator.displayName = "InputOTPSeparator"

export { InputOTP, InputOTPGroup, InputOTPSlot, InputOTPSeparator }

client/src/components/StemFlowLogo.tsx.content:
import stemFlowLogo from "@assets/WhatsApp_Image_2026-02-12_at_21.06.10_1770926836861.jpeg";

interface StemFlowLogoProps {
  size?: "sm" | "md" | "lg" | "xl";
  showText?: boolean;
  className?: string;
  variant?: "default" | "light";
}

export function StemFlowLogo({ size = "md", showText = true, className = "", variant = "default" }: StemFlowLogoProps) {
  const sizeClasses = {
    sm: "h-8",
    md: "h-10",
    lg: "h-14",
    xl: "h-20",
  };

  const iconOnlySizes = {
    sm: "h-6",
    md: "h-8",
    lg: "h-12",
    xl: "h-16",
  };

  return (
    <div className={`flex items-center ${className}`}>
      <img 
        src={stemFlowLogo} 
        alt="STEMflow" 
        className={`${showText ? sizeClasses[size] : iconOnlySizes[size]} w-auto object-contain ${variant === "light" ? "brightness-[10] contrast-50" : ""}`}
        data-testid="logo-stemflow"
      />
    </div>
  );
}

export function StemFlowSlogan({ className = "" }: { className?: string }) {
  return (
    <p className={`font-medium italic tracking-wide ${className}`}>
      Scroll. Learn. Level Up.
    </p>
  );
}

client/src/index.css.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

/* LIGHT MODE - STEM FLOW African Innovation Theme
   Palette:
   - Primary Blue (Confiance, Technologie): #0B3C5D
   - Primary Green (Progression, Innovation): #00C896
   - Secondary Yellow (Énergie, Gamification): #F5B700
   - Light Gray (Confort visuel): #F4F6F8
   - Soft Black (Texte): #1E1E1E
*/
:root {
  --button-outline: rgba(0,0,0, .10);
  --badge-outline: rgba(0,0,0, .05);

  --opaque-button-border-intensity: -8;

  --elevate-1: rgba(0,0,0, .03);
  --elevate-2: rgba(0,0,0, .08);

  /* Deep tech blue tinted backgrounds */
  --background: 210 25% 97%;
  --foreground: 0 0% 12%;
  --border: 200 20% 88%;

  --card: 0 0% 100%;
  --card-foreground: 0 0% 12%;
  --card-border: 200 20% 90%;

  --sidebar: 200 30% 96%;
  --sidebar-foreground: 200 40% 15%;
  --sidebar-border: 200 20% 88%;
  --sidebar-primary: 200 78% 20%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 164 60% 94%;
  --sidebar-accent-foreground: 164 80% 28%;
  --sidebar-ring: 164 100% 39%;

  --popover: 0 0% 100%;
  --popover-foreground: 0 0% 12%;
  --popover-border: 200 20% 88%;

  /* Primary: Deep tech blue - Confiance, Savoir, Technologie */
  --primary: 200 78% 20%;
  --primary-foreground: 0 0% 100%;

  --secondary: 210 20% 94%;
  --secondary-foreground: 200 40% 20%;

  --muted: 210 15% 94%;
  --muted-foreground: 200 15% 40%;

  /* Accent: Green energy - Progression, Réussite, Innovation */
  --accent: 164 100% 39%;
  --accent-foreground: 0 0% 100%;

  --destructive: 0 72% 51%;
  --destructive-foreground: 0 0% 100%;

  --input: 200 20% 88%;
  --ring: 164 100% 39%;

  /* Charts use all brand colors */
  --chart-1: 200 78% 20%;
  --chart-2: 164 100% 39%;
  --chart-3: 46 100% 48%;
  --chart-4: 200 60% 45%;
  --chart-5: 164 70% 50%;

  --font-sans: 'Inter', 'DM Sans', sans-serif;
  --font-serif: Georgia, serif;
  --font-mono: 'JetBrains Mono', monospace;
  --radius: .5rem;
  --shadow-2xs: 0px 1px 2px 0px rgba(11, 60, 93, 0.05);
  --shadow-xs: 0px 1px 3px 0px rgba(11, 60, 93, 0.08);
  --shadow-sm: 0px 2px 4px 0px rgba(11, 60, 93, 0.08), 0px 1px 2px -1px rgba(11, 60, 93, 0.05);
  --shadow: 0px 4px 6px -1px rgba(11, 60, 93, 0.1), 0px 2px 4px -2px rgba(11, 60, 93, 0.08);
  --shadow-md: 0px 6px 10px -2px rgba(11, 60, 93, 0.1), 0px 3px 6px -3px rgba(11, 60, 93, 0.08);
  --shadow-lg: 0px 10px 15px -3px rgba(11, 60, 93, 0.1), 0px 4px 6px -4px rgba(11, 60, 93, 0.08);
  --shadow-xl: 0px 20px 25px -5px rgba(11, 60, 93, 0.1), 0px 8px 10px -6px rgba(11, 60, 93, 0.08);
  --shadow-2xl: 0px 25px 50px -12px rgba(11, 60, 93, 0.25);
  --tracking-normal: 0em;
  --spacing: 0.25rem;

  --sidebar-primary-border: hsl(var(--sidebar-primary));
  --sidebar-primary-border: hsl(from hsl(var(--sidebar-primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --sidebar-accent-border: hsl(var(--sidebar-accent));
  --sidebar-accent-border: hsl(from hsl(var(--sidebar-accent)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --primary-border: hsl(var(--primary));
  --primary-border: hsl(from hsl(var(--primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --secondary-border: hsl(var(--secondary));
  --secondary-border: hsl(from hsl(var(--secondary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --muted-border: hsl(var(--muted));
  --muted-border: hsl(from hsl(var(--muted)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --accent-border: hsl(var(--accent));
  --accent-border: hsl(from hsl(var(--accent)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
  --destructive-border: hsl(var(--destructive));
  --destructive-border: hsl(from hsl(var(--destructive)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
}

/* DARK MODE - STEM FLOW African Innovation Theme */
.dark {
  --button-outline: rgba(255,255,255, .10);
  --badge-outline: rgba(255,255,255, .05);

  --opaque-button-border-intensity: 9;

  --elevate-1: rgba(255,255,255, .04);
  --elevate-2: rgba(255,255,255, .09);

  --background: 200 25% 7%;
  --foreground: 210 15% 95%;
  --border: 200 20% 18%;

  --card: 200 20% 10%;
  --card-foreground: 210 15% 95%;
  --card-border: 200 18% 18%;

  --sidebar: 200 22% 9%;
  --sidebar-foreground: 200 15% 90%;
  --sidebar-border: 200 18% 15%;
  --sidebar-primary: 200 70% 35%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 164 50% 18%;
  --sidebar-accent-foreground: 164 80% 70%;
  --sidebar-ring: 164 100% 45%;

  --popover: 200 20% 10%;
  --popover-foreground: 210 15% 95%;
  --popover-border: 200 18% 18%;

  /* Primary: Deep tech blue - brighter in dark mode */
  --primary: 200 70% 40%;
  --primary-foreground: 0 0% 100%;

  --secondary: 200 18% 18%;
  --secondary-foreground: 200 15% 85%;

  --muted: 200 15% 15%;
  --muted-foreground: 200 12% 55%;

  /* Accent: Green energy - brighter in dark mode */
  --accent: 164 100% 45%;
  --accent-foreground: 0 0% 100%;

  --destructive: 0 72% 55%;
  --destructive-foreground: 0 0% 100%;

  --input: 200 18% 22%;
  --ring: 164 100% 45%;

  --chart-1: 200 70% 45%;
  --chart-2: 164 100% 50%;
  --chart-3: 46 100% 55%;
  --chart-4: 200 55% 55%;
  --chart-5: 164 65% 55%;

  --shadow-2xs: 0px 1px 2px 0px rgba(0, 0, 0, 0.3);
  --shadow-xs: 0px 1px 3px 0px rgba(0, 0, 0, 0.4);
  --shadow-sm: 0px 2px 4px 0px rgba(0, 0, 0, 0.3), 0px 1px 2px -1px rgba(0, 0, 0, 0.2);
  --shadow: 0px 4px 6px -1px rgba(0, 0, 0, 0.4), 0px 2px 4px -2px rgba(0, 0, 0, 0.3);
  --shadow-md: 0px 6px 10px -2px rgba(0, 0, 0, 0.4), 0px 3px 6px -3px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0px 10px 15px -3px rgba(0, 0, 0, 0.5), 0px 4px 6px -4px rgba(0, 0, 0, 0.4);
  --shadow-xl: 0px 20px 25px -5px rgba(0, 0, 0, 0.5), 0px 8px 10px -6px rgba(0, 0, 0, 0.4);
  --shadow-2xl: 0px 25px 50px -12px rgba(0, 0, 0, 0.7);
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
  }
}

/* Custom gradient utilities for STEM FLOW - African Innovation */
@layer utilities {
  /* Main gradient: Blue to Green (Tech → Progression) */
  .gradient-stem {
    background: linear-gradient(135deg, hsl(200 78% 20%) 0%, hsl(164 100% 39%) 100%);
  }

  .gradient-stem-dark {
    background: linear-gradient(135deg, hsl(200 70% 35%) 0%, hsl(164 100% 45%) 100%);
  }

  .gradient-stem-text {
    background: linear-gradient(135deg, hsl(200 78% 25%) 0%, hsl(164 100% 39%) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .gradient-stem-border {
    border-image: linear-gradient(135deg, hsl(200 78% 20%) 0%, hsl(164 100% 39%) 100%) 1;
  }

  /* Energy gradient: Green to Yellow (Progression → Motivation) */
  .gradient-energy {
    background: linear-gradient(135deg, hsl(164 100% 39%) 0%, hsl(46 100% 48%) 100%);
  }

  /* Innovation gradient: Blue to Yellow (Tech → Énergie) */
  .gradient-innovation {
    background: linear-gradient(135deg, hsl(200 78% 20%) 0%, hsl(46 100% 48%) 100%);
  }

  /* Full brand gradient: Blue → Green → Yellow */
  .gradient-african {
    background: linear-gradient(135deg, hsl(200 78% 20%) 0%, hsl(164 100% 39%) 50%, hsl(46 100% 48%) 100%);
  }

  input[type="search"]::-webkit-search-cancel-button {
    @apply hidden;
  }

  [contenteditable][data-placeholder]:empty::before {
    content: attr(data-placeholder);
    color: hsl(var(--muted-foreground));
    pointer-events: none;
  }

  .no-default-hover-elevate {}
  .no-default-active-elevate {}

  .toggle-elevate::before,
  .toggle-elevate-2::before {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: -1;
  }

  .toggle-elevate.toggle-elevated::before {
    background-color: var(--elevate-2);
  }

  .border.toggle-elevate::before {
    inset: -1px;
  }

  .hover-elevate:not(.no-default-hover-elevate),
  .active-elevate:not(.no-default-active-elevate),
  .hover-elevate-2:not(.no-default-hover-elevate),
  .active-elevate-2:not(.no-default-active-elevate) {
    position: relative;
    z-index: 0;
  }

  .hover-elevate:not(.no-default-hover-elevate)::after,
  .active-elevate:not(.no-default-active-elevate)::after,
  .hover-elevate-2:not(.no-default-hover-elevate)::after,
  .active-elevate-2:not(.no-default-active-elevate)::after {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: 999;
  }

  .hover-elevate:hover:not(.no-default-hover-elevate)::after,
  .active-elevate:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-1);
  }

  .hover-elevate-2:hover:not(.no-default-hover-elevate)::after,
  .active-elevate-2:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-2);
  }

  .border.hover-elevate:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate-2:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate-2:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate:not(.no-hover-interaction-elevate)::after {
    inset: -1px;
  }

  .scroll-smooth {
    scroll-behavior: smooth;
    -webkit-overflow-scrolling: touch;
  }

  .scrollbar-hide {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .scrollbar-hide::-webkit-scrollbar {
    display: none;
  }
}

