                <circle
                  cx="44" cy="44" r="38"
                  fill="none"
                  stroke="hsl(var(--muted))"
                  strokeWidth="4"
                />
                <circle
                  cx="44" cy="44" r="38"
                  fill="none"
                  stroke="hsl(var(--accent))"
