        </Card>

        <Button
          variant="outline"
          className="w-full text-destructive"
          onClick={handleLogout}
          data-testid="button-logout"
        >
          <LogOut className="h-4 w-4 mr-2" />
          Se d\u00e9connecter
        </Button>
      </main>

      <BottomNav />
    </div>
  );
}

